const body = $json.body;

// Check if photo exists
if (!body.photo) {
  // No photo - pass through
  return [{ json: body }];
}

// Photo already compressed by the browser (canvas resize at 82% JPEG quality)
// Just prepare the binary for upload
const photoBase64 = body.photo;
const originalFilename = body.photoFilename || 'photo.jpg';

const timestamp = Date.now();
const randomStr = Math.random().toString(36).substring(2, 8);
const cleanFilename = `${timestamp}_${randomStr}.jpg`;

const binaryData = Buffer.from(photoBase64, 'base64');

return [{
  json: {
    ...body,
    photoFilename: cleanFilename,
    hasPhoto: true,
    // Store base64 for Vision call later (only manual uploads, not OG)
    photoBase64: photoBase64
  },
  binary: {
    photo: {
      data: binaryData.toString('base64'),
      mimeType: 'image/jpeg',
      fileName: cleanFilename
    }
  }
}];

// Only run Vision on manual photo uploads (not OG images)
// Check photoSource — OG path sets photoSource: 'og'
const photoSource = $('Handle Photo Upload').first().json.photoSource || 'manual';
const photoBase64 = $('Handle Photo Upload').first().json.photoBase64 || null;

if (photoSource === 'og' || !photoBase64) {
  // Skip Vision for OG images — the OG title/description already covers content
  return [{ json: { image_caption: null, skip_vision: true } }];
}

const dataUrl = `data:image/jpeg;base64,${photoBase64}`;

return [{ json: { dataUrl, skip_vision: false } }];

