const body = $json.body || $json;

// Only attempt OG download if there's an ogImageUrl and no manual photo
if (body.ogImageUrl && body.ogImageUrl.startsWith('http')) {
  return [{ json: { ...body, hasOGImage: true } }];
}

// No OG image — pass through
return [{ json: { ...body, hasOGImage: false } }];

const body = $('Check OG Image').first().json;

const timestamp = Date.now();
const randomStr = Math.random().toString(36).substring(2, 8);
const cleanFilename = `og_${timestamp}_${randomStr}.jpg`;

const currentItem = $input.item;
const binaryData = currentItem.binary?.data;

if (!binaryData) {
  throw new Error('Binary missing. Keys: ' + JSON.stringify(Object.keys(currentItem.binary || {})));
}

return [{
  json: {
    ...body,
    photoFilename: cleanFilename,
    hasPhoto: true,
    photoSource: 'og',
    ogImageUrl: null
  },
  binary: {
    photo: {
      data: binaryData.data,
      mimeType: binaryData.mimeType || 'image/jpeg',
      fileName: cleanFilename,
      fileSize: binaryData.fileSize,
      id: binaryData.id
    }
  }
}];

parameters.text:
=You are enriching discovery data for semantic search. Use ONLY the provided inputs below.

INPUTS:
- Title: {{ $('Handle Photo Upload').item.json.title }}
- Photo/AI description: {{ $('Handle Photo Upload').item.json.description || 'none' }}
- Personal note (user's own words): {{ $('Handle Photo Upload').item.json.personalNote || 'none' }}
- Category: {{ $('Handle Photo Upload').item.json.type }}
- Address: {{ $('Handle Photo Upload').item.json.address || 'none' }}
- URL: {{ $('Handle Photo Upload').item.json.url || 'none' }}
- Live image caption: {{ $('Merge Vision Result').item.json.image_caption || 'none' }}

NOTE: 'Photo/AI description' was generated from the photo at prefill time. 'Personal note' is what the user actually wrote. 'Live image caption' is a fresh Vision analysis of the same photo.

CRITICAL: Base enrichment on title + all description signals above. Do not invent unrelated content.

TASK:
Generate a JSON response with:
{
  "enriched_description": "<synthesize photo description + image caption into rich context, max 80 words. Do not include the personal note — that stays separate.>",
  "keywords": ["<5-8 relevant keywords based on category, description, and image caption>"],
  "feed_card_summary": "<5-10 word punchy summary. No punctuation at end. No quotes. Examples: Amazing rooftop bar with city views | Best ramen in Tokyo near Shinjuku | Hidden beach perfect for sunset picnics>"
}

Keyword examples by category:
- For medical/healthcare: ["healthcare", "medical", "specialist", "clinic", "doctor", location]
- For coffee shops: ["coffee", "cafe", "wifi", "atmosphere", location]
- For restaurants: ["food", "dining", "cuisine", "restaurant", location]

Return ONLY valid JSON with no explanation or markdown formatting.

