// Parse AI response
let ai;
try {
  const text = $json.text || '{}';
  const cleaned = text.replace(/```json\n?|```\n?/g, '').trim();
  ai = JSON.parse(cleaned);
} catch (e) {
  ai = { enriched_description: '', keywords: [], feed_card_summary: '' };
}

// Get original data from Handle Photo Upload
const originalData = $('Handle Photo Upload').first().json;

// Resolve photo URL
let photoUrl = null;

if (originalData.photoFilename) {
  photoUrl = `https://hedywkwmgkvojujvczqr.supabase.co/storage/v1/object/public/recommendation-photos/${originalData.photoFilename}`;
} else {
  try {
    const ogFilename = $('Prepare OG Photo for Upload').first()?.json?.photoFilename;
    if (ogFilename) {
      photoUrl = `https://hedywkwmgkvojujvczqr.supabase.co/storage/v1/object/public/recommendation-photos/${ogFilename}`;
    }
  } catch (e) {
    photoUrl = null;
  }
}

// Clean feed_card_summary — strip surrounding quotes
const rawSummary = ai.feed_card_summary || '';
const feedCardSummary = rawSummary.replace(/^["']/g, '').replace(/["']$/g, '').trim();

const payload = {
  title: originalData.title || 'Untitled',
  description: originalData.description || '',
  enriched_description: ai.enriched_description || originalData.description || '',
  keywords: Array.isArray(ai.keywords) ? ai.keywords : [],
  feed_card_summary: feedCardSummary,
  type: (originalData.type || 'place').toLowerCase(),
  address: originalData.address || null,
  URL: originalData.url ? [originalData.url] : [],
  added_by: originalData.UserID || null,
  added_by_name: originalData.addedBy || 'Unknown',
  family_id: originalData.familyId || null,
  network_layer: 1,
  language: 'en',
  photo_url: photoUrl,
  personal_note: originalData.personalNote || null,
  metadata: {
    source: 'web_form',
    created: new Date().toISOString()
  }
};

const embedding_text = [
  payload.title,
  payload.enriched_description,
  payload.personal_note,
  payload.type,
  payload.added_by_name,
  payload.keywords.join(', '),
  payload.address
].filter(Boolean).join('\n');

return [{ json: { payload, embedding_text } }];

const payload = $('Build Record').first().json.payload;
const embedding = $json.data[0].embedding;

return [{
  json: {
    ...payload,
    embedding: embedding
  }
}];
